const GPT_VIDEO_OMNI_SUBMIT_URL = 'https://api.wuyinkeji.com/api/async/video_google_omni';
const GPT_IMAGE2_DETAIL_URL = 'https://api.wuyinkeji.com/api/async/detail';
const BANANA_SUBMIT_URL = 'https://nanobanana.cloud/api/submit';
const BANANA_RESULT_URL = 'https://nanobanana.cloud/api/query';
const GOOGLE_BANANA_API_BASE = 'https://generativelanguage.googleapis.com/v1beta/models/';
