async function submitBanana(prompt, BANANA_KEY, referenceImageUrls = [DEFAULT_REFERENCE_IMAGE_URL]){
  const urls = Array.isArray(referenceImageUrls) && referenceImageUrls.length ? referenceImageUrls.filter(Boolean).slice(0, 5) : [DEFAULT_REFERENCE_IMAGE_URL];
  const referenceImageUrl = urls[0] || DEFAULT_REFERENCE_IMAGE_URL;
  const form = new FormData();
  form.append('prompt', prompt);
  form.append('model', 'nano-banana-pro');
  form.append('mode', 'image-to-image');
  form.append('aspectRatio', '16:9');
  form.append('width', '1920');
  form.append('height', '1080');
  form.append('imageSize', '1K');
  form.append('imageUrl', referenceImageUrl);
  urls.forEach(url => {
    form.append('imageUrls[]', url);
    form.append('image_urls[]', url);
  });
  const resp = await fetch(BANANA_SUBMIT_URL, {
    method: 'POST',
    headers: { Authorization: `Bearer ${BANANA_KEY}` },
    body: form
  });
  const text = await resp.text();
  let data;
  try { data = JSON.parse(text); } catch { data = { raw: text }; }
  if(!resp.ok) throw new Error(`submit ${resp.status}: ${text.slice(0, 500)}`);
  if(data?.code === 401 || data?.message === 'Unauthorized') throw new Error('Banana 官方鉴权失败：服务端 API Key 未被官方接口接受');
  const taskId = extractTaskId(data);
  if(!taskId) throw new Error(`no taskId: ${text.slice(0, 500)}`);
  return taskId;
}

async function pollBanana(taskId, BANANA_KEY){
  for(let i = 0; i < 36; i++){
    await sleep(5000);
    const resp = await fetch(BANANA_RESULT_URL, {
      method: 'POST',
      headers: { Authorization: `Bearer ${BANANA_KEY}`, 'Content-Type': 'application/json' },
      body: JSON.stringify({ taskId })
    });
    const text = await resp.text();
    let data;
    try { data = JSON.parse(text); } catch { data = { raw: text }; }
    if(!resp.ok) continue;
    const status = data?.data?.status || data?.status;
    const imageUrl = extractImageUrl(data);
    if(['succeeded','success','completed'].includes(status) && imageUrl) return imageUrl;
    if(['failed','error'].includes(status)) throw new Error(`task failed: ${text.slice(0, 500)}`);
  }
  throw new Error('生成超时，请稍后重试');
}

async function generateGoogleBanana(prompt, GOOGLE_BANANA_KEY, referenceImageUrls = [DEFAULT_REFERENCE_IMAGE_URL]){
  const parts = [{ text: prompt }];
  const urls = Array.isArray(referenceImageUrls) ? referenceImageUrls.filter(Boolean).slice(0, 5) : [];
  for(const imageUrl of urls){
    if(imageUrl === DEFAULT_REFERENCE_IMAGE_URL) continue;
    if(String(imageUrl).startsWith('data:image/')){
      const parsed = parseDataImage(imageUrl);
      parts.push({ inline_data: { mime_type: parsed.contentType, data: bytesToBase64(parsed.bytes) } });
      continue;
    }
    const imgResp = await fetch(imageUrl);
    if(!imgResp.ok) throw new Error('Google Banana reference fetch failed: ' + imgResp.status);
    const contentType = (imgResp.headers.get('content-type') || 'image/png').split(';')[0].trim();
    if(!contentType.startsWith('image/')) throw new Error('Google Banana reference is not an image');
    const buffer = await imgResp.arrayBuffer();
    if(buffer.byteLength > REFERENCE_MAX_BYTES) throw new Error('Google Banana reference image too large');
    parts.push({ inline_data: { mime_type: contentType, data: bytesToBase64(new Uint8Array(buffer)) } });
  }
  const resp = await fetch(GOOGLE_BANANA_API_BASE + GOOGLE_BANANA_MODEL + ':generateContent?key=' + encodeURIComponent(GOOGLE_BANANA_KEY), {
    method: 'POST',
    headers: { 'Content-Type':'application/json' },
    body: JSON.stringify({ contents:[{ role:'user', parts }], generationConfig:{ responseModalities:['TEXT','IMAGE'] } })
  });
  const text = await resp.text();
  let data;
  try { data = JSON.parse(text); } catch { data = { raw:text }; }
  if(!resp.ok) throw new Error('Google Banana ' + resp.status + ': ' + text.slice(0, 500));
  const image = extractGoogleImage(data);
  if(!image?.data) throw new Error('Google Banana no image: ' + text.slice(0, 500));
  return { taskId:'google-banana-' + Date.now().toString(36), image };
}

