async function checkVideoGoogleOmni(taskId, GPT_IMAGE2_KEY){
  const detailUrl = GPT_IMAGE2_DETAIL_URL + '?key=' + encodeURIComponent(GPT_IMAGE2_KEY) + '&id=' + encodeURIComponent(taskId);
  const resp = await fetch(detailUrl, { headers:{ Authorization: GPT_IMAGE2_KEY } });
  const text = await resp.text();
  let data; try { data = JSON.parse(text); } catch { data = { raw: text }; }
  if(!resp.ok){
    if([502, 503, 504, 524].includes(resp.status)) return { done:false, status:'UPSTREAM_RETRY_' + resp.status };
    throw new Error(`Video status ${resp.status}: ${text.slice(0, 500)}`);
  }
  const d = data?.data || {};
  const status = d.status;
  const videoUrl = extractVideoUrlDeep(data?.data?.result || data?.result || data?.data || data);
  if(videoUrl && status !== 0) return { done:true, videoUrl, status };
  if(status === 2 && videoUrl) return { done:true, videoUrl, status };
  if(status === 3) throw new Error(`Video task failed: ${text.slice(0, 500)}`);
  return { done:false, status: status ?? 'IN_PROGRESS' };
}

